"use client"
import React, { useState } from 'react'
import { ImportAdapter } from './ImportAdapter'
import { usePosts } from './PostsProvider'
import type { Post } from '../types/data.d'

export default function AddPostModal({ open, onClose, onImported }: { open: boolean; onClose: () => void; onImported?: (p: Post) => void }) {
  const [url, setUrl] = useState('')
  const [loading, setLoading] = useState(false)
  const { addPost } = usePosts()

  if (!open) return null

  async function handleImport() {
    if (!url) return
    setLoading(true)
    try {
      const result = await ImportAdapter.importFromInstagramUrl(url)

      const newPost: Post = {
        id: `p-${Date.now()}`,
        thumbnail: result.thumbnail,
        author: result.authorHandle,
        caption: result.caption,
        categoryId: 'c-unsorted',
        collectionIds: [],
        savedAt: new Date().toISOString()
      }

      addPost(newPost)
      onImported?.(newPost)
      setUrl('')
      onClose()
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center">
      <div className="absolute inset-0 bg-black/40" onClick={onClose} />
      <div className="relative bg-white rounded-md p-6 w-full max-w-md shadow-lg">
        <h3 className="text-lg font-semibold mb-3">Import Post from Instagram</h3>
        <input
          value={url}
          onChange={(e) => setUrl(e.target.value)}
          placeholder="Paste Instagram post URL"
          className="w-full border px-3 py-2 rounded"
        />
        <div className="mt-4 flex justify-end gap-2">
          <button className="px-3 py-1 rounded border" onClick={onClose} disabled={loading}>
            Cancel
          </button>
          <button className="px-3 py-1 rounded bg-slate-800 text-white" onClick={handleImport} disabled={loading}>
            {loading ? 'Importing…' : 'Import'}
          </button>
        </div>
      </div>
    </div>
  )
}
